INSERT INTO parks (name, region, park_type, address_line, city, state, zip_code, hours, total_fields, max_capacity, amenities, description, image_url, image_alt, card_summary, latitude, longitude, is_featured) VALUES
('Jones Beach State Park', 'Long Island', 'Beach', '1 Ocean Parkway', 'Wantagh', 'NY', '11793', 'Open daily; beachfront closes at sunset seasonally', 2, 250, 'Ocean beach, boardwalk, swimming, fishing, boating, surfing, nature center, accessible beach mats', 'A classic Long Island oceanfront park with 6.5 miles of Atlantic beach, a boardwalk, swimming areas, fishing access, water recreation, and major seasonal events.', 'https://images.unsplash.com/photo-1507525428034-b723cf961d3e?auto=format&fit=crop&w=1200&q=80', 'Sandy ocean beach and waves', 'Atlantic beachfront, boardwalk, fishing, swimming, and seasonal events.', 40.596200, -73.503000, 1),
('Letchworth State Park', 'Finger Lakes', 'Gorge / Waterfalls', '1 Letchworth State Park', 'Castile', 'NY', '14427', 'Open year-round; park facilities vary by season', 1, 180, 'Hiking trails, waterfalls, overlooks, camping, cabins, museum, picnic areas, pool, rafting, horseback riding', 'Known as the Grand Canyon of the East, Letchworth follows the Genesee River through a deep gorge with three major waterfalls and miles of scenic trails.', 'https://images.unsplash.com/photo-1500530855697-b586d89ba3ee?auto=format&fit=crop&w=1200&q=80', 'Forest trail and scenic overlook', 'Genesee River gorge, waterfalls, overlooks, trails, camping, and outdoor programs.', 42.673000, -78.004800, 1),
('Niagara Falls State Park', 'Niagara', 'Landmark / Waterfalls', '332 Prospect Street', 'Niagara Falls', 'NY', '14303', 'Open year-round; attractions and facilities vary by season', 1, 220, 'Waterfall overlooks, visitor center, trails, picnic areas, scenic trolley, educational programs', 'America''s oldest state park centers on the world-famous Niagara Falls and offers waterfall overlooks, gorge access, trails, visitor services, and year-round sightseeing.', 'https://images.unsplash.com/photo-1528909514045-2fa4ac7a08ba?auto=format&fit=crop&w=1200&q=80', 'Mist rising from a major waterfall', 'World-famous waterfall views, gorge walks, visitor services, and sightseeing.', 43.082800, -79.074200, 1),
('Watkins Glen State Park', 'Finger Lakes', 'Gorge / Waterfalls', '1009 N Franklin Street', 'Watkins Glen', 'NY', '14891', 'Open daily; Gorge Trail typically seasonal', 1, 120, 'Gorge trail, 19 waterfalls, camping, cabins, pool, fishing, picnic areas, playground, pavilions', 'The best-known Finger Lakes gorge park, Watkins Glen features a stream descending past cliffs and 19 waterfalls along a dramatic gorge trail.', 'https://images.unsplash.com/photo-1506744038136-46273834b3fb?auto=format&fit=crop&w=1200&q=80', 'Gorge trail with waterfall', 'Famous gorge trail, waterfalls, stone paths, camping, swimming, and picnic areas.', 42.380100, -76.873300, 1),
('Montauk Point State Park', 'Long Island', 'Coastal / Lighthouse', '2000 Montauk Highway', 'Montauk', 'NY', '11954', 'Open year-round; hours and facilities vary by season', 1, 150, 'Ocean views, lighthouse views, nature trails, fishing, seal watching, cross-country skiing', 'At the eastern tip of Long Island, Montauk Point offers views where the Atlantic Ocean meets Block Island Sound, plus trails, fishing, and lighthouse scenery.', 'https://images.unsplash.com/photo-1464822759023-fed622ff2c3b?auto=format&fit=crop&w=1200&q=80', 'Coastal cliffs near a lighthouse', 'Atlantic and Block Island Sound views, lighthouse scenery, trails, fishing, and wildlife.', 41.072200, -71.860300, 1),
('Minnewaska State Park Preserve', 'Palisades', 'Preserve / Trails', '5281 Route 44-55', 'Kerhonkson', 'NY', '12446', 'Opens daily at 9:00 AM; closing times vary seasonally', 1, 140, 'Lake Minnewaska, carriage roads, cliffs, waterfalls, hiking, biking, climbing, visitor center, scenic overlooks', 'A large Shawangunk ridge preserve with more than 24,000 acres of cliffs, lakes, carriage roads, waterfalls, forests, and long-distance views.', 'https://images.unsplash.com/photo-1441974231531-c6227db76b6e?auto=format&fit=crop&w=1200&q=80', 'Wooded trail through tall trees', 'Shawangunk ridge views, lakes, cliffs, carriage roads, hiking, biking, and climbing.', 41.739200, -74.234900, 1),
('Bear Mountain State Park', 'Palisades', 'Mountain / Recreation', 'Route 9W North', 'Bear Mountain', 'NY', '10911', 'Open year-round; facility hours vary by season', 1, 200, 'Hiking, biking, lake and river fishing, picnic groves, pool, ice rink, Trailside Museums and Zoo, Merry-Go-Round', 'Set in rugged Hudson Highlands terrain, Bear Mountain offers trails, picnic areas, lake and river recreation, seasonal skating, museums, and wide views from Perkins Memorial Tower.', 'https://images.unsplash.com/photo-1500534314209-a25ddb2bd429?auto=format&fit=crop&w=1200&q=80', 'Mountain landscape and forest', 'Hudson Highlands trails, picnic areas, fishing, skating, museums, zoo, and scenic tower views.', 41.312900, -73.988400, 0),
('Robert H. Treman State Park', 'Finger Lakes', 'Gorge / Waterfalls', '105 Enfield Falls Road', 'Ithaca', 'NY', '14850', 'Open year-round; facilities and swimming are seasonal', 1, 120, 'Gorge trails, waterfalls, swimming, camping, cabins, pavilions, hiking, picnic areas', 'Robert H. Treman protects the rugged Enfield Glen gorge, with waterfall trails, Lucifer Falls, wooded scenery, camping, and a stream-fed swimming area.', 'https://images.unsplash.com/photo-1500534623283-312aade485b7?auto=format&fit=crop&w=1200&q=80', 'Waterfall gorge in a forest', 'Enfield Glen gorge, waterfall trails, Lucifer Falls, camping, cabins, and swimming.', 42.401000, -76.548000, 0),
('Taughannock Falls State Park', 'Finger Lakes', 'Waterfalls / Lake', '1740 Taughannock Boulevard', 'Trumansburg', 'NY', '14886', 'Open year-round; beach and facilities vary by season', 1, 160, 'Waterfall overlook, gorge and rim trails, Cayuga Lake beach, marina, boat launch, camping, cabins', 'Taughannock Falls plunges 215 feet past high gorge walls, with rim and gorge trails plus Cayuga Lake camping, cabins, beach, marina, and boat launch nearby.', 'https://images.unsplash.com/photo-1518837695005-2083093ee35b?auto=format&fit=crop&w=1200&q=80', 'Tall waterfall in a rocky gorge', '215-foot waterfall, gorge and rim trails, Cayuga Lake beach, marina, camping, and cabins.', 42.538700, -76.608000, 0),
('Green Lakes State Park', 'Central New York', 'Lake / Forest', '7900 Green Lakes Road', 'Fayetteville', 'NY', '13066', 'Open year-round; swimming and facilities vary by season', 1, 150, 'Glacial lakes, beach, trails, old-growth forest, golf, camping, cabins, playgrounds', 'Green Lakes is known for rare meromictic lakes, old-growth forest, trails, a beach, camping, cabins, and outdoor education opportunities.', 'https://images.unsplash.com/photo-1500534314209-a25ddb2bd429?auto=format&fit=crop&w=1200&q=80', 'Clear lake surrounded by forest', 'Rare glacial lakes, old-growth forest, beach, trails, golf, camping, and education programs.', 43.058600, -75.971600, 0),
('Buttermilk Falls State Park', 'Finger Lakes', 'Gorge / Waterfalls', '112 E Buttermilk Falls Road', 'Ithaca', 'NY', '14850', 'Open year-round; swimming and camping seasonal', 1, 110, 'Gorge trail, waterfalls, swimming, camping, cabins, picnic areas, playing fields', 'Buttermilk Falls features a cascading creek, gorge and rim trails, wooded areas, picnic grounds, camping, cabins, and a seasonal natural swimming area.', 'https://images.unsplash.com/photo-1432405972618-c60b0225b8f9?auto=format&fit=crop&w=1200&q=80', 'Cascading waterfall in forest', 'Cascading gorge, rim trails, swimming, camping, cabins, picnic areas, and playing fields.', 42.417000, -76.521000, 0),
('Allegany State Park - Red House Area', 'Allegany', 'Forest / Camping', '2373 ASP, Rte 1, Suite 3', 'Salamanca', 'NY', '14779', 'Open year-round; campground, cabin, and swimming schedules vary', 1, 200, 'Camping, cabins, cottages, beach, boating, biking, hiking, snowmobiling, nature museum, picnic areas', 'The Red House Area of Allegany State Park is centered on Red House Lake and features camping, cabins, a beach, bike paths, boating, hiking, winter recreation, and a natural history museum.', 'https://images.unsplash.com/photo-1500534314209-a25ddb2bd429?auto=format&fit=crop&w=1200&q=80', 'Lake and forest landscape', 'Red House Lake, cabins, campsites, beach, boating, hiking, biking, and nature museum.', 42.100600, -78.749400, 0),
('Saratoga Spa State Park', 'Saratoga/Capital', 'Historic / Recreation', '19 Roosevelt Drive', 'Saratoga Springs', 'NY', '12866', 'Open year-round; facility hours vary by season', 1, 250, 'Mineral springs, trails, pools, golf, picnic areas, SPAC, museums, performing arts, winter recreation', 'A National Historic Landmark, Saratoga Spa State Park combines mineral springs, classical architecture, cultural destinations, pools, golf, trails, picnic areas, and SPAC.', 'https://images.unsplash.com/photo-1510798831971-661eb04b3739?auto=format&fit=crop&w=1200&q=80', 'Historic park landscape', 'Mineral springs, historic architecture, SPAC, pools, golf, trails, picnic areas, and museums.', 43.055000, -73.805000, 0),
('Moreau Lake State Park', 'Saratoga/Capital', 'Lake / Camping', '605 Old Saratoga Road', 'Gansevoort', 'NY', '12831', 'Open year-round; facility hours vary by season', 1, 120, 'Lake, beach, camping, cabins, boating, fishing, hiking, nature center, picnic areas, pavilions', 'Moreau Lake sits among hardwood forests, pine stands, and rocky ridges, with a sandy beach, quiet campgrounds, cabins, boating, fishing, trails, and a nature center.', 'https://images.unsplash.com/photo-1501785888041-af3ef285b470?auto=format&fit=crop&w=1200&q=80', 'Lake with wooded shoreline', 'Lake beach, secluded campgrounds, cabins, boating, fishing, trails, pavilions, and nature center.', 43.234400, -73.727800, 0),
('Grafton Lakes State Park', 'Saratoga/Capital', 'Lakes / Recreation', '254 Grafton Lakes State Park Way', 'Grafton', 'NY', '12082', 'Open year-round; beach and facilities seasonal', 1, 130, 'Ponds, beach, boating, fishing, hiking, biking, snowshoeing, cross-country skiing, picnic areas', 'Grafton Lakes is set on a forested mountain ridge and includes several ponds, swimming, boating, fishing, trails, picnicking, and winter recreation.', 'https://images.unsplash.com/photo-1448375240586-882707db888b?auto=format&fit=crop&w=1200&q=80', 'Forest lake in summer', 'Forested ridge park with ponds, beach, boating, fishing, trails, picnicking, and winter recreation.', 42.769200, -73.465600, 0),
('Wellesley Island State Park', 'Thousand Islands', 'Island / Camping', '44927 Cross Island Road', 'Fineview', 'NY', '13640', 'Open seasonally for many facilities; camping season varies', 1, 180, 'Camping, marina, boat launches, beach, fishing, nature center, golf, trails, cabins', 'The largest camping complex in the Thousand Islands region, Wellesley Island offers hundreds of campsites, fishing, a marina, boat launches, a river beach, trails, and a nature center.', 'https://images.unsplash.com/photo-1500534314209-a25ddb2bd429?auto=format&fit=crop&w=1200&q=80', 'Island shoreline and forest', 'Thousand Islands camping, marina, boat launches, beach, fishing, trails, golf, and nature center.', 44.316400, -76.008800, 0),
('Orient Beach State Park', 'Long Island', 'Beach / Maritime Forest', '40000 Main Road', 'Orient', 'NY', '11957', 'Open seasonally; hours and beach operations vary', 1, 120, 'Gardiners Bay beach, maritime forest, kayaking, fishing, windsurfing, paddle boarding, biking, picnic pavilion', 'At Long Island''s North Fork tip, Orient Beach protects Gardiners Bay shoreline, rare maritime forest, marsh, wildlife habitat, beach recreation, paddling, biking, and picnic areas.', 'https://images.unsplash.com/photo-1507525428034-b723cf961d3e?auto=format&fit=crop&w=1200&q=80', 'Quiet bay beach', 'Gardiners Bay shoreline, rare maritime forest, kayaking, fishing, beach recreation, biking, and birding.', 41.143900, -72.243600, 0),
('Caumsett State Historic Park Preserve', 'Long Island', 'Historic Preserve / Trails', '25 Lloyd Harbor Road', 'Lloyd Harbor', 'NY', '11743', 'Open year-round; hours vary by season', 1, 140, 'Bridle paths, hiking, biking, jogging, nature trails, gardens, fishing, scuba diving by permit', 'Caumsett occupies a scenic peninsula on Long Island Sound, with bridle paths, hiking and biking routes, woodlands, meadows, rocky shoreline, salt marsh, gardens, and historic landscapes.', 'https://images.unsplash.com/photo-1500530855697-b586d89ba3ee?auto=format&fit=crop&w=1200&q=80', 'Woodland path through park preserve', 'Long Island Sound peninsula with bridle paths, trails, woodlands, meadows, shoreline, gardens, and fishing.', 40.924300, -73.475100, 0),
('Bethpage State Park', 'Long Island', 'Golf / Recreation', '99 Quaker Meeting House Road', 'Farmingdale', 'NY', '11735', 'Open year-round; golf and facility hours vary', 1, 250, 'Golf courses, picnic areas, polo field, hiking, biking, bridle paths, restaurant, pro shop', 'Bethpage State Park is known for its golf complex, including the Black Course, and also offers picnic areas, trails, bridle paths, recreation fields, and event facilities.', 'https://images.unsplash.com/photo-1535131749006-b7f58c99034b?auto=format&fit=crop&w=1200&q=80', 'Golf course fairway', 'Golf courses, picnic areas, polo field, trails, bridle paths, restaurant, and recreation fields.', 40.742600, -73.456600, 0),
('Belmont Lake State Park', 'Long Island', 'Lake / Day Use', 'Southern State Parkway Exit 38', 'North Babylon', 'NY', '11703', 'Sunrise to sunset, year-round', 1, 130, 'Lake, picnic areas, playgrounds, boating rentals, fishing, biking, hiking, informal sports, pavilions', 'Belmont Lake is a 463-acre day-use park centered on Belmont Lake and Carlls Creek, with picnic areas, trails, boating rentals, fishing, playgrounds, and informal sports.', 'https://images.unsplash.com/photo-1500534314209-a25ddb2bd429?auto=format&fit=crop&w=1200&q=80', 'Lake path in a public park', 'Belmont Lake, Carlls Creek, picnic areas, boating rentals, fishing, biking, playgrounds, and trails.', 40.736300, -73.334000, 0),
('Sunken Meadow State Park', 'Long Island', 'Beach / Golf', 'Rte. 25A and Sunken Meadow Parkway', 'Kings Park', 'NY', '11754', 'Open year-round; beach and facilities vary by season', 1, 200, 'Long Island Sound beach, boardwalk, picnic areas, ball fields, playgrounds, golf, hiking, environmental programs', 'Sunken Meadow offers Long Island Sound views, beach and boardwalk recreation, picnic and group areas, ball fields, playgrounds, golf, trails, and public programs.', 'https://images.unsplash.com/photo-1507525428034-b723cf961d3e?auto=format&fit=crop&w=1200&q=80', 'Beach and shoreline', 'Long Island Sound beach, boardwalk, picnic areas, fields, playgrounds, golf, trails, and programs.', 40.905800, -73.260300, 0),
('Robert Moses State Park - Long Island', 'Long Island', 'Beach / Recreation', '600 Robert Moses State Parkway', 'Babylon', 'NY', '11702', 'Open year-round; beach and facilities vary by season', 1, 220, 'Ocean beach, swimming, surfing, surf-fishing, pitch and putt golf, picnic areas, beach access mats', 'Robert Moses State Park is a barrier-beach destination on Fire Island with miles of ocean beach, swimming, surfing, surf-fishing, picnic areas, and access to the Fire Island Lighthouse area.', 'https://images.unsplash.com/photo-1507525428034-b723cf961d3e?auto=format&fit=crop&w=1200&q=80', 'Ocean beach with waves', 'Fire Island ocean beach, swimming, surfing, surf-fishing, picnic areas, and pitch-and-putt golf.', 40.625300, -73.260700, 0),
('Rockland Lake State Park', 'Palisades', 'Lake / Recreation', '299 Rockland Lake Road', 'Valley Cottage', 'NY', '10989', 'Open year-round; pool and facilities vary by season', 1, 180, 'Lake trail, pool complex, picnic areas, boat launch, hiking, tennis, golf, fishing', 'Rockland Lake sits on a ridge above the west bank of the Hudson River and offers a paved lake loop, picnic areas, fishing, hiking, tennis, golf, and a large pool complex.', 'https://images.unsplash.com/photo-1501785888041-af3ef285b470?auto=format&fit=crop&w=1200&q=80', 'Lake with wooded shoreline', 'Hudson Valley lake loop, pool complex, picnic areas, fishing, hiking, tennis, and golf.', 41.142600, -73.922200, 0),
('Nyack Beach State Park', 'Palisades', 'Riverfront / Trails', '698 N Broadway', 'Upper Nyack', 'NY', '10960', 'Open year-round; hours vary by season', 1, 100, 'Hudson Riverfront, hiking, biking, fishing, picnicking, kayaking, windsurfing, cross-country skiing', 'Nyack Beach provides 61 acres of Hudson River waterfront in Rockland County, popular for picnicking, hiking, bicycling, fishing, paddling, windsurfing, and winter trail use.', 'https://images.unsplash.com/photo-1500534314209-a25ddb2bd429?auto=format&fit=crop&w=1200&q=80', 'Riverfront park trail', 'Hudson Riverfront picnicking, hiking, biking, fishing, kayaking, windsurfing, and winter trails.', 41.121800, -73.914600, 0),
('Sampson State Park', 'Finger Lakes', 'Lake / Camping', '6096 Route 96A', 'Romulus', 'NY', '14541', 'Open year-round; camping and facilities vary by season', 1, 160, 'Seneca Lake camping, beach, marina, boat launch, picnic areas, trails, military museum', 'On the eastern shore of Seneca Lake, Sampson offers camping, boating, sunsets, a marina, multiple boat launches, beach use, picnic areas, trails, and military history exhibits.', 'https://images.unsplash.com/photo-1501785888041-af3ef285b470?auto=format&fit=crop&w=1200&q=80', 'Lake shoreline at sunset', 'Seneca Lake camping, beach, marina, boat launches, picnic areas, trails, and sunsets.', 42.729700, -76.902100, 0),
('Keuka Lake State Park', 'Finger Lakes', 'Lake / Camping', '3560 Pepper Road', 'Bluff Point', 'NY', '14478', 'Open seasonally for most camping and beach facilities', 1, 120, 'Keuka Lake beach, camping, picnic areas, playground, boat launch, fishing, vineyard views', 'Keuka Lake State Park sits in Finger Lakes wine country with lake views, camping areas, a swimming beach, picnic facilities, fishing, playgrounds, and boat access.', 'https://images.unsplash.com/photo-1500534314209-a25ddb2bd429?auto=format&fit=crop&w=1200&q=80', 'Lake and wooded hills', 'Keuka Lake views, camping, beach, picnic areas, fishing, playground, boat launch, and wine-country scenery.', 42.575200, -77.124700, 0),
('Fair Haven Beach State Park', 'Finger Lakes', 'Lake Ontario Beach', '14985 State Park Road', 'Fair Haven', 'NY', '13064', 'Open year-round; beach and camping seasonal', 1, 150, 'Lake Ontario beach, swimming, camping, cabins, boating, fishing, hiking, picnic areas, pavilions', 'Fair Haven Beach State Park features a Lake Ontario shoreline, sandy beach, campgrounds, cabins, boating, fishing, hiking, picnic areas, and views over nearby bluffs and woodlands.', 'https://images.unsplash.com/photo-1507525428034-b723cf961d3e?auto=format&fit=crop&w=1200&q=80', 'Great lake beach shoreline', 'Lake Ontario beach, swimming, camping, cabins, boating, fishing, hiking, and picnic areas.', 43.319400, -76.705800, 0);
