INSERT INTO news (title, topic, published_date, region, summary, content, image_url, image_alt, card_summary, tag, is_featured, news_status) VALUES
('Spring trail readiness updates across NYS parks', 'alerts', '2026-04-14', 'Statewide', 'Trail teams are preparing signage, cleanup areas, and visitor guidance ahead of the spring season.', 'Maintenance crews are reviewing priority routes, refreshing signage, and preparing visitor guidance so spring trail use is safer and easier to navigate.', 'https://images.unsplash.com/photo-1500530855697-b586d89ba3ee?auto=format&fit=crop&w=1200&q=80', 'Forest trail in spring', 'Spring trail readiness and visitor guidance updates.', 'Trail Conditions', 1, 'published'),
('Weekend volunteer day expands native planting projects', 'community', '2026-04-10', 'Hudson Valley', 'Community volunteers are helping improve park landscapes, restore native plant beds, and support seasonal beautification efforts.', 'Volunteer teams will help prepare native plant beds, remove light debris, and support seasonal improvements at select park locations.', 'https://images.unsplash.com/photo-1466692476868-aef1dfb1e735?auto=format&fit=crop&w=1200&q=80', 'Volunteers gardening outdoors', 'Volunteer event supporting native planting projects.', 'Community', 0, 'published'),
('New family nature programs added to the events calendar', 'events', '2026-04-06', 'Finger Lakes', 'The public events calendar now highlights more kid-friendly hikes, ranger talks, and beginner outdoor learning sessions.', 'Families can browse new beginner hikes, guided ranger talks, and hands-on outdoor learning sessions in the events calendar.', 'https://images.unsplash.com/photo-1502082553048-f009c37129b9?auto=format&fit=crop&w=1200&q=80', 'Family hiking through woods', 'New family-friendly nature programs added.', 'Programs', 0, 'published'),
('Visitor safety reminder for waterfront and gorge areas', 'safety', '2026-04-03', 'Southern Tier', 'Guests are encouraged to stay on marked trails, observe posted guidance, and prepare for changing weather conditions.', 'Park staff remind visitors to follow posted signage near water, use designated trails, and prepare for changing spring weather.', 'https://images.unsplash.com/photo-1500534623283-312aade485b7?auto=format&fit=crop&w=1200&q=80', 'Scenic gorge and river area', 'Waterfront and gorge safety reminders.', 'Safety', 0, 'published'),
('Historic site exhibits receive a refreshed digital spotlight', 'parks', '2026-03-29', 'Capital Region', 'Updated site content helps visitors explore park history, exhibits, and destination highlights more easily online.', 'The public site now gives historic destinations a clearer place to feature stories, exhibits, and visitor planning information.', 'https://images.unsplash.com/photo-1510798831971-661eb04b3739?auto=format&fit=crop&w=1200&q=80', 'Historic park landscape', 'Digital spotlight for historic park exhibits.', 'Park Spotlight', 0, 'published'),
('Donation campaign supports seasonal improvements and programming', 'support', '2026-03-24', 'Statewide', 'Public support can help fund park improvements, community programming, and visitor experience projects across the state.', 'Donations support seasonal improvements, public programming, visitor materials, and accessibility-focused project needs.', 'https://images.unsplash.com/photo-1488521787991-ed7bbaae773c?auto=format&fit=crop&w=1200&q=80', 'Hands holding seedlings', 'Donation campaign for seasonal improvements.', 'Support', 0, 'published');
